const folder = env.get('log_folder');
const prefix = env.get('file_prefix');
const includeFull = env.get('include_full_payload') === 'true';

const now = new Date();
const pad = n => String(n).padStart(2, '0');
const dateStr = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
const filePath = `${folder}/${prefix}_${dateStr}.jsonl`;

const entry = {
    logged_at: now.toISOString(),
    result: includeFull ? msg.payload : {
        overall_status: msg.payload && msg.payload.overall_status,
        pass_count: msg.payload && msg.payload.pass_count,
        fail_count: msg.payload && msg.payload.fail_count
    }
};

const entryText = JSON.stringify(entry);
msg._file_path = filePath;
msg._entry_text = entryText;
msg.filename = filePath;
msg.payload = entryText;
return msg;

// This node runs AFTER the file write. Reconstruct a clean response.
msg.payload = {
    success: true,
    file_path: msg._file_path,
    bytes_written: (msg._entry_text || '').length,
    timestamp: new Date().toISOString()
};

delete msg._entry_text;
delete msg._file_path;
delete msg.filename;
return msg;
